import { describe, expect, it } from "vitest";

import type { BackupInfo } from "@/api/agents";
import type { AuthStartResult } from "@/api/auth";
import type { FileTreeEntry } from "@/api/files";
import type { Personality } from "@/api/personalities";
import type { AgentInfo, AgentStatus, GatewayVersionInfo } from "./types";
import { vestadApiFixtures } from "./vestad-api-fixtures";

// Cross-language API contract: the fixtures are generated by vestad's Rust test
// (serve.rs::api_contract_fixtures_up_to_date) using the production serialization code.
// Each `satisfies` below is a COMPILE-TIME check (fails `npm run check` / vitest) that
// vestad's wire format is accepted by the TypeScript type the web app uses for it.
//
// Direction matters: vestad may send extra fields (TS ignores them), and TS unions may
// have extra members (like the client-side "restarting" status), but every field a TS
// type requires must come over the wire with a compatible shape.

describe("vestad API contract", () => {
  it("every AgentStatus value vestad emits is known to the web app", () => {
    const statuses =
      vestadApiFixtures.agent_statuses satisfies readonly AgentStatus[];
    expect(statuses).toContain("alive");
    expect(statuses).toContain("not_authenticated");
  });

  it("control WS agents message rows satisfy AgentInfo", () => {
    const message = vestadApiFixtures.agents_ws_message;
    expect(message.type).toBe("agents");
    const agents = message.agents satisfies readonly AgentInfo[];
    expect(agents.length).toBeGreaterThan(0);
    expect(agents[0].services.dashboard.port).toBe(8080);
    expect(agents[0].services.dashboard.rev).toBe(3);
  });

  it("backup listings satisfy BackupInfo for every backup type", () => {
    const backups = vestadApiFixtures.backups satisfies readonly BackupInfo[];
    expect(backups.map((backup) => backup.backup_type)).toEqual([
      "manual",
      "daily",
      "weekly",
      "monthly",
      "pre_restore",
    ]);
  });

  it("auth flow response satisfies AuthStartResult", () => {
    const auth = vestadApiFixtures.auth_start satisfies AuthStartResult;
    expect(auth.auth_url).toContain("https://");
    expect(auth.session_id).toBeTruthy();
  });

  it("personality satisfies Personality", () => {
    const personality = vestadApiFixtures.personality satisfies Personality;
    expect(personality.name).toBeTruthy();
  });

  it("tree entries satisfy FileTreeEntry", () => {
    const entry = vestadApiFixtures.tree_entry satisfies FileTreeEntry;
    expect(entry.is_dir).toBe(false);
  });

  it("version response satisfies GatewayVersionInfo", () => {
    const version = vestadApiFixtures.version satisfies GatewayVersionInfo;
    expect(version.api_compat).toBe("0.2");
  });
});
